`))}const C=Object.entries(Es).filter(([B,E])=>E.reviewed===!1).map(([B,E])=>["Name: "+B,"Description: "+E.description,"Typical dosage: "+(E.typicalDosage||"Not specified"),"Form: "+(E.form||"Not specified"),"Mechanism: "+(E.mechanism||"Not specified"),"Cautions: "+(E.cautions||"None noted."),"Evidence: "+E.evidence+" (examine.com: "+E.evidenceUrl+")","When to use: "+(E.whenToUse||"Not specified"),"Allergens: "+(E.allergens&&E.allergens.length?E.allergens.join(", "):"None"),"Diet excludes: "+(E.dietExcludes&&E.dietExcludes.length?E.dietExcludes.join(", "):"Compatible with all diets")].join(`
